import React, { useState } from 'react';

const LOGO_URL = 'data:image/png;base64,';

const LoginPage = ({ onForgotPassword }) => {
  const [showPassword, setShowPassword] = useState(false);
  const [focusedField, setFocusedField] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);

  const handleSubmit = (event) => {
    event.preventDefault();
    setIsSubmitting(true);
    window.setTimeout(() => setIsSubmitting(false), 900);
  };

  const theme = {
    page: isDarkMode ? 'bg-[#151d1a] text-[#F8F7F2]' : 'bg-[#F8F7F2] text-grad-gray-900',
    header: isDarkMode ? 'border-white/10 bg-[#151d1a]/85' : 'border-[#EBEAE4] bg-[#F8F7F2]/80',
    card: isDarkMode ? 'bg-[#1d2823]/95 border-white/10 shadow-black/35' : 'bg-[#FAF9F6]/95 border-[#EBEAE4] shadow-gray-200/70',
    panel: isDarkMode ? 'bg-[#1d2823]/80 border-white/10' : 'bg-[#FAF9F6]/80 border-[#EBEAE4]',
    text: isDarkMode ? 'text-[#F8F7F2]' : 'text-grad-gray-900',
    muted: isDarkMode ? 'text-[#b9c4bd]' : 'text-grad-gray-600',
    faint: isDarkMode ? 'text-[#8f9b94]' : 'text-grad-gray-400',
    input: isDarkMode ? '!bg-[#111a16] border-white/10 text-[#F8F7F2] placeholder:text-[#728078]' : '!bg-white border-gray-200 text-grad-gray-900',
    soft: isDarkMode ? 'bg-[#111a16]/70 hover:bg-[#111a16]' : 'bg-white/60 hover:bg-white',
  };

  return (
    <div className={`relative min-h-screen flex flex-col overflow-hidden transition-colors duration-500 ${theme.page}`}>
      <style>{`
        @keyframes floatSlow { 0%, 100% { transform: translate3d(0, 0, 0) scale(1); } 50% { transform: translate3d(20px, -24px, 0) scale(1.08); } }
        @keyframes floatReverse { 0%, 100% { transform: translate3d(0, 0, 0) scale(1); } 50% { transform: translate3d(-18px, 18px, 0) scale(0.96); } }
        @keyframes cardIn { from { opacity: 0; transform: translateY(24px) scale(0.98); } to { opacity: 1; transform: translateY(0) scale(1); } }
        @keyframes shimmer { 0% { transform: translateX(-120%); } 100% { transform: translateX(120%); } }
        @keyframes orbit { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .motion-bg-one { animation: floatSlow 12s ease-in-out infinite; }
        .motion-bg-two { animation: floatReverse 14s ease-in-out infinite; }
        .motion-card { animation: cardIn 700ms cubic-bezier(0.22, 1, 0.36, 1) both; }
        .motion-shine::before { content: ''; position: absolute; inset: 0; background: linear-gradient(90deg, transparent, rgba(255,255,255,0.45), transparent); animation: shimmer 3.8s ease-in-out infinite; }
        .logo-orbit::after { content: ''; position: absolute; inset: -8px; border: 1px dashed rgba(197, 160, 89, 0.45); border-radius: 9999px; animation: orbit 18s linear infinite; }
        @media (prefers-reduced-motion: reduce) { .motion-bg-one, .motion-bg-two, .motion-card, .motion-shine::before, .logo-orbit::after { animation: none !important; } }
      `}</style>

      <div className="pointer-events-none absolute inset-0 overflow-hidden">
        <div className={`motion-bg-one absolute -top-24 -left-20 h-72 w-72 rounded-full blur-3xl ${isDarkMode ? 'bg-[#6ee7b7]/10' : 'bg-[#1a4231]/10'}`} />
        <div className={`motion-bg-two absolute top-28 -right-24 h-80 w-80 rounded-full blur-3xl ${isDarkMode ? 'bg-amber-400/10' : 'bg-amber-500/10'}`} />
        <div className={`absolute bottom-16 left-1/2 h-56 w-56 -translate-x-1/2 rounded-full blur-3xl ${isDarkMode ? 'bg-[#1a4231]/30' : 'bg-white/60'}`} />
      </div>

      <header className={`relative z-10 p-6 border-b backdrop-blur-xl transition-colors duration-500 ${theme.header}`}>
        <div className="max-w-7xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-3 group/logo">
            <div className="w-14 h-14 flex items-center justify-center overflow-visible transition-transform duration-500 group-hover/logo:-rotate-2 group-hover/logo:scale-105">
              <img src={LOGO_URL} alt="Yarmouk University Logo" className="w-full h-full object-contain" />
            </div>
            <div>
              <h1 className={`text-xl font-bold leading-tight transition-colors ${theme.text}`}>GradArchive</h1>
              <p className={`text-[10px] uppercase tracking-widest font-semibold transition-colors ${theme.muted}`}>Faculty of IT &amp; CS - YU</p>
            </div>
          </div>

          <button
            type="button"
            onClick={() => setIsDarkMode((mode) => !mode)}
            aria-label={isDarkMode ? 'Switch to day mode' : 'Switch to dark mode'}
            aria-pressed={isDarkMode}
            className={`group flex items-center gap-3 rounded-full border px-4 py-2 shadow-sm transition-all duration-300 hover:-translate-y-0.5 hover:shadow-lg ${theme.panel}`}
          >
            <span className={`relative h-7 w-12 rounded-full p-1 transition-colors ${isDarkMode ? 'bg-[#F8F7F2]/20' : 'bg-[#1a4231]/10'}`}>
              <span className={`absolute top-1 h-5 w-5 rounded-full bg-[#1a4231] shadow-md transition-all duration-300 ${isDarkMode ? 'translate-x-5 bg-amber-300' : 'translate-x-0'}`} />
            </span>
            <span className={`hidden sm:inline text-xs font-bold uppercase tracking-widest transition-colors ${theme.muted}`}>{isDarkMode ? 'Day Mode' : 'Dark Mode'}</span>
          </button>
        </div>
      </header>

      <main className="relative z-10 flex-grow flex items-center justify-center p-6 bg-transparent">
        <div className="w-full max-w-6xl grid lg:grid-cols-[1fr_440px] items-center gap-10">
          <section className="hidden lg:block">
            <div className="max-w-xl">
              <div className={`inline-flex items-center gap-2 rounded-full border px-4 py-2 shadow-sm mb-6 transition-colors ${theme.panel}`}>
                <span className="h-2 w-2 rounded-full bg-amber-500" />
                <span className={`text-xs font-bold uppercase tracking-widest transition-colors ${theme.muted}`}>Graduation Project Archive</span>
              </div>
              <h2 className={`text-6xl font-black leading-[0.95] tracking-tight transition-colors ${theme.text}`}>Your academic work, organized with purpose.</h2>
              <p className={`mt-6 text-lg leading-8 transition-colors ${theme.muted}`}>A cleaner gateway for students, supervisors, and faculty partners to access verified graduation project records.</p>
              <div className="mt-8 grid grid-cols-3 gap-3">
                {[['24/7', 'Access'], ['YU', 'Verified'], ['IT', 'Focused']].map(([value, label]) => (
                  <div key={label} className={`rounded-2xl border p-4 shadow-sm transition-all hover:-translate-y-1 hover:shadow-lg ${theme.panel}`}>
                    <p className="text-2xl font-black text-grad-green">{value}</p>
                    <p className={`mt-1 text-[10px] font-bold uppercase tracking-widest ${theme.faint}`}>{label}</p>
                  </div>
                ))}
              </div>
            </div>
          </section>

          <div className={`motion-card relative w-full max-w-md mx-auto rounded-[2rem] shadow-2xl border p-8 sm:p-10 backdrop-blur-xl overflow-hidden transition-colors duration-500 ${theme.card}`}>
            <div className="motion-shine absolute inset-x-0 top-0 h-1 bg-gradient-to-r from-transparent via-amber-500/70 to-transparent" />
            <div className="text-center mb-10">
              <div className="flex flex-col items-center justify-center gap-4 mb-3">
                <div className="logo-orbit relative w-24 h-28 overflow-visible flex items-center justify-center rounded-full bg-transparent shadow-none">
                  <img src={LOGO_URL} alt="Yarmouk University Logo" className="relative z-10 w-full h-full object-contain transition-transform duration-700 hover:scale-105" />
                </div>
                <div>
                  <h2 className={`text-4xl font-bold tracking-tight transition-colors ${isDarkMode ? 'text-white' : 'text-grad-green'}`}>GradArchive</h2>
                  <div className="mx-auto mt-3 h-1 w-20 rounded-full bg-gradient-to-r from-transparent via-amber-500 to-transparent" />
                </div>
              </div>
              <p className={`text-sm font-medium transition-colors ${theme.muted}`}>Please enter your credentials to access the archive.</p>
            </div>

            <form className="space-y-6" onSubmit={handleSubmit}>
              <div onFocus={() => setFocusedField('email')} onBlur={() => setFocusedField('')}>
                <label className={`block text-sm font-semibold mb-2 transition-colors ${theme.text}`}>University Email</label>
                <div className={`relative rounded-xl transition-all duration-300 ${focusedField === 'email' ? 'shadow-lg shadow-[#1a4231]/10 -translate-y-0.5' : ''}`}>
                  <span className={`absolute left-3 top-1/2 -translate-y-1/2 transition-colors ${focusedField === 'email' ? 'text-grad-green' : 'text-gray-400'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>
                  </span>
                  <input type="email" placeholder="student@yu.edu.jo" className={`input-field transition-colors ${theme.input}`} />
                </div>
              </div>

              <div onFocus={() => setFocusedField('password')} onBlur={() => setFocusedField('')}>
                <div className="flex justify-between items-center mb-2">
                  <label className={`text-sm font-semibold transition-colors ${theme.text}`}>Password</label>
                  <button type="button" onClick={() => onForgotPassword?.()} className="text-xs font-medium text-amber-600 hover:text-amber-700 transition-colors hover:underline underline-offset-4">Forgot password?</button>
                </div>
                <div className={`relative rounded-xl transition-all duration-300 ${focusedField === 'password' ? 'shadow-lg shadow-[#1a4231]/10 -translate-y-0.5' : ''}`}>
                  <span className={`absolute left-3 top-1/2 -translate-y-1/2 transition-colors ${focusedField === 'password' ? 'text-grad-green' : 'text-gray-400'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                  </span>
                  <input type={showPassword ? 'text' : 'password'} placeholder="************" className={`input-field pr-12 transition-colors ${theme.input}`} />
                  <button type="button" onClick={() => setShowPassword(!showPassword)} aria-label={showPassword ? 'Hide password' : 'Show password'} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-grad-green transition-all hover:scale-110">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      {showPassword ? <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.477 0-8.268-2.943-9.542-7a9.97 9.97 0 012.223-3.592m3.31-2.046A9.956 9.956 0 0112 5c4.478 0 8.268 2.943 9.542 7a9.973 9.973 0 01-4.132 5.236M3 3l18 18" /> : <><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></>}
                    </svg>
                  </button>
                </div>
              </div>

              <div className={`flex items-center gap-2 rounded-xl px-3 py-2 transition-all ${theme.soft}`}>
                <input type="checkbox" id="remember" className="w-4 h-4 rounded border-gray-300 text-grad-green focus:ring-grad-green transition-all" />
                <label htmlFor="remember" className={`text-sm cursor-pointer select-none transition-colors ${theme.muted}`}>Remember this device for 30 days</label>
              </div>

              <button type="submit" disabled={isSubmitting} className={`btn-primary mt-4 py-4 text-lg transition-all duration-300 ${isSubmitting ? 'opacity-90 scale-[0.99]' : 'hover:-translate-y-0.5 hover:shadow-xl'}`}>
                <span>{isSubmitting ? 'Checking Access...' : 'Sign In'}</span>
                {!isSubmitting && <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>}
              </button>
            </form>
          </div>
        </div>
      </main>

      <footer className={`relative z-10 p-6 border-t transition-colors duration-500 ${theme.header}`}>
        <div className="max-w-7xl mx-auto flex items-center justify-center text-xs font-medium">
          <p className={`transition-colors ${theme.faint}`}>© {new Date().getFullYear()} GradArchive. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
};

export default LoginPage;
